<template><div class="page-content"><PageHeader eyebrow="Delivery system" title="DevCenter Projects" description="选择一个有权限访问的 Project，进入对应的应用交付 Workspace。"/><section class="surface project-list"><div class="surface-header"><div><h3>Accessible projects</h3><p>项目权限与基础设施边界由 Project Center 提供</p></div><el-button :loading="loading" @click="load">刷新</el-button></div><div class="cards"><article v-for="p in items" :key="p.id" @click="$router.push(`/devcenter/projects/${p.id}`)"><span>▦</span><div><h3>{{p.name}}</h3><p>{{p.description||'Application delivery workspace'}}</p><small>{{p.application_count}} Applications · Last Release {{p.last_release?format(p.last_release):'—'}}</small></div><b>→</b></article></div><EmptyState v-if="!items.length&&!loading" title="没有可访问的 Project" description="请联系 Project Owner 添加成员权限，或前往 Project Center 创建项目。"/></section></div></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{projectApi}from'../api/project';import type{Project}from'../types';import PageHeader from'../components/common/PageHeader.vue';import EmptyState from'../components/common/EmptyState.vue';const items=ref<Project[]>([]),loading=ref(false),format=(v:string)=>new Date(v).toLocaleString('zh-CN',{hour12:false});async function load(){loading.value=true;try{items.value=await projectApi.list()}finally{loading.value=false}}onMounted(load);</script>
<style scoped>.project-list{overflow:hidden}.cards{display:grid;grid-template-columns:1fr 1fr;gap:12px;padding:16px}.cards article{padding:17px;border:1px solid var(--border-soft);border-radius:10px;display:flex;align-items:center;gap:13px;cursor:pointer;background:var(--surface-soft)}.cards article:hover{border-color:#66718a}.cards article>span{width:38px;height:38px;display:grid;place-items:center;border-radius:9px;background:var(--primary-soft);color:#aaa0ff}.cards article>div{flex:1}.cards h3,.cards p{margin:0}.cards h3{font-size:14px}.cards p,.cards small{color:var(--muted);font-size:11px}.cards p{margin:5px 0}.cards b{color:var(--primary)}</style>
